import re
from defusedxml import ElementTree as SafeET
from xml.etree.ElementTree import Element
from datetime import datetime, timezone
from .exceptions import SAMLValidationError, SAMLExpiredError


SAML_PROTOCOL_NS = 'urn:oasis:names:tc:SAML:2.0:protocol'
SAML_ASSERTION_NS = 'urn:oasis:names:tc:SAML:2.0:assertion'
XMLDSIG_NS = 'http://www.w3.org/2000/09/xmldsig#'

NAMESPACES = {
    'samlp': SAML_PROTOCOL_NS,
    'saml': SAML_ASSERTION_NS,
    'ds': XMLDSIG_NS,
}


class SAMLXMLValidator:
    """Validates SAML XML structure and extracts data."""

    def __init__(self, xml_string):
        if not xml_string or not xml_string.strip():
            raise SAMLValidationError("Empty SAML response XML.")
        self.xml_string = xml_string
        self.root = None
        self._parse_xml()

    def _parse_xml(self):
        """Parse XML safely using defusedxml to prevent XXE attacks."""
        try:
            self.root = SafeET.fromstring(self.xml_string)
        except Exception as e:
            raise SAMLValidationError(f"Failed to parse SAML XML: {str(e)}")

    def _get_local_name(self, element):
        """Get the local name of an element, stripping namespace."""
        tag = element.tag
        if '}' in tag:
            return tag.split('}', 1)[1]
        return tag

    def _get_namespace(self, element):
        """Get the namespace of an element."""
        tag = element.tag
        if tag.startswith('{'):
            return tag.split('}', 1)[0][1:]
        return ''

    def validate_structure(self):
        """Validate the basic SAML Response XML structure."""
        errors = []

        # Check root element is a SAML Response
        root_local = self._get_local_name(self.root)
        root_ns = self._get_namespace(self.root)

        if root_local != 'Response':
            errors.append(
                f"Root element must be 'Response', got '{root_local}'."
            )

        if root_ns != SAML_PROTOCOL_NS:
            errors.append(
                f"Root element namespace must be '{SAML_PROTOCOL_NS}', "
                f"got '{root_ns}'."
            )

        # Check for required attributes on Response
        response_id = self.root.get('ID')
        if not response_id:
            errors.append("Response element missing required 'ID' attribute.")

        version = self.root.get('Version')
        if version != '2.0':
            errors.append(
                f"SAML Version must be '2.0', got '{version}'."
            )

        issue_instant = self.root.get('IssueInstant')
        if not issue_instant:
            errors.append("Response element missing 'IssueInstant' attribute.")

        # Check Status element
        status = self.root.find(f'{{{SAML_PROTOCOL_NS}}}Status')
        if status is None:
            errors.append("Response missing required 'Status' element.")
        else:
            status_code = status.find(f'{{{SAML_PROTOCOL_NS}}}StatusCode')
            if status_code is None:
                errors.append("Status missing required 'StatusCode' element.")
            else:
                status_value = status_code.get('Value', '')
                if 'Success' not in status_value:
                    status_msg_elem = status.find(
                        f'{{{SAML_PROTOCOL_NS}}}StatusMessage'
                    )
                    status_msg = (
                        status_msg_elem.text if status_msg_elem is not None
                        else 'Unknown error'
                    )
                    errors.append(
                        f"SAML authentication failed. Status: {status_value}. "
                        f"Message: {status_msg}"
                    )

        # Check for Assertion
        assertion = self.root.find(f'{{{SAML_ASSERTION_NS}}}Assertion')
        if assertion is None:
            errors.append("Response missing required 'Assertion' element.")
        else:
            self._validate_assertion(assertion, errors)

        if errors:
            raise SAMLValidationError(
                "SAML XML validation failed: " + "; ".join(errors)
            )

        return True

    def _validate_assertion(self, assertion, errors):
        """Validate the Assertion element structure."""
        # Check Assertion ID
        assertion_id = assertion.get('ID')
        if not assertion_id:
            errors.append("Assertion missing required 'ID' attribute.")

        # Check Issuer
        issuer = assertion.find(f'{{{SAML_ASSERTION_NS}}}Issuer')
        if issuer is None or not issuer.text:
            errors.append("Assertion missing required 'Issuer' element.")

        # Check Subject
        subject = assertion.find(f'{{{SAML_ASSERTION_NS}}}Subject')
        if subject is None:
            errors.append("Assertion missing required 'Subject' element.")
        else:
            name_id = subject.find(f'{{{SAML_ASSERTION_NS}}}NameID')
            if name_id is None or not name_id.text:
                errors.append("Subject missing required 'NameID' element.")

        # Check Conditions
        conditions = assertion.find(f'{{{SAML_ASSERTION_NS}}}Conditions')
        if conditions is not None:
            self._validate_conditions(conditions, errors)

        # Check AuthnStatement
        authn_statement = assertion.find(
            f'{{{SAML_ASSERTION_NS}}}AuthnStatement'
        )
        if authn_statement is None:
            errors.append(
                "Assertion missing required 'AuthnStatement' element."
            )

    def _validate_conditions(self, conditions, errors):
        """Validate assertion conditions including time validity."""
        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')

        now = datetime.now(timezone.utc)

        if not_before:
            try:
                not_before_dt = self._parse_saml_datetime(not_before)
                # Allow 5 minutes clock skew
                from datetime import timedelta
                if now < not_before_dt - timedelta(minutes=5):
                    errors.append(
                        f"Assertion not yet valid. NotBefore: {not_before}"
                    )
            except ValueError:
                errors.append(
                    f"Invalid NotBefore datetime format: {not_before}"
                )

        if not_on_or_after:
            try:
                not_after_dt = self._parse_saml_datetime(not_on_or_after)
                from datetime import timedelta
                if now >= not_after_dt + timedelta(minutes=5):
                    errors.append(
                        f"Assertion has expired. NotOnOrAfter: {not_on_or_after}"
                    )
            except ValueError:
                errors.append(
                    f"Invalid NotOnOrAfter datetime format: {not_on_or_after}"
                )

    @staticmethod
    def _parse_saml_datetime(dt_string):
        """Parse SAML datetime string to datetime object."""
        # Handle various SAML datetime formats
        formats = [
            '%Y-%m-%dT%H:%M:%SZ',
            '%Y-%m-%dT%H:%M:%S.%fZ',
            '%Y-%m-%dT%H:%M:%S%z',
        ]
        for fmt in formats:
            try:
                dt = datetime.strptime(dt_string, fmt)
                if dt.tzinfo is None:
                    dt = dt.replace(tzinfo=timezone.utc)
                return dt
            except ValueError:
                continue
        raise ValueError(f"Unable to parse datetime: {dt_string}")

    def get_response_id(self):
        """Get the Response ID."""
        return self.root.get('ID')

    def get_assertion(self):
        """Get the Assertion element."""
        return self.root.find(f'{{{SAML_ASSERTION_NS}}}Assertion')

    def get_assertion_id(self):
        """Get the Assertion ID."""
        assertion = self.get_assertion()
        if assertion is not None:
            return assertion.get('ID')
        return None

    def get_issuer(self):
        """Get the Issuer from the Response or Assertion."""
        # Try Response-level issuer first
        issuer = self.root.find(f'{{{SAML_ASSERTION_NS}}}Issuer')
        if issuer is not None and issuer.text:
            return issuer.text.strip()

        # Fall back to Assertion-level issuer
        assertion = self.get_assertion()
        if assertion is not None:
            issuer = assertion.find(f'{{{SAML_ASSERTION_NS}}}Issuer')
            if issuer is not None and issuer.text:
                return issuer.text.strip()

        return None

    def get_name_id(self):
        """Extract NameID from the assertion."""
        assertion = self.get_assertion()
        if assertion is None:
            raise SAMLValidationError("No assertion found in SAML response.")

        subject = assertion.find(f'{{{SAML_ASSERTION_NS}}}Subject')
        if subject is None:
            raise SAMLValidationError("No Subject found in assertion.")

        name_id_elem = subject.find(f'{{{SAML_ASSERTION_NS}}}NameID')
        if name_id_elem is None or not name_id_elem.text:
            raise SAMLValidationError("No NameID found in Subject.")

        return {
            'value': name_id_elem.text.strip(),
            'format': name_id_elem.get('Format', ''),
            'sp_name_qualifier': name_id_elem.get('SPNameQualifier', ''),
            'name_qualifier': name_id_elem.get('NameQualifier', ''),
        }

    def get_session_index(self):
        """Extract SessionIndex from AuthnStatement."""
        assertion = self.get_assertion()
        if assertion is None:
            return None

        authn_statement = assertion.find(
            f'{{{SAML_ASSERTION_NS}}}AuthnStatement'
        )
        if authn_statement is not None:
            return authn_statement.get('SessionIndex')
        return None

    def get_attributes(self):
        """Extract all attributes from the assertion's AttributeStatement."""
        assertion = self.get_assertion()
        if assertion is None:
            return {}

        attributes = {}
        attr_statement = assertion.find(
            f'{{{SAML_ASSERTION_NS}}}AttributeStatement'
        )
        if attr_statement is None:
            return attributes

        for attribute in attr_statement.findall(
            f'{{{SAML_ASSERTION_NS}}}Attribute'
        ):
            attr_name = attribute.get('Name', '')
            attr_friendly = attribute.get('FriendlyName', '')
            values = []

            for attr_value in attribute.findall(
                f'{{{SAML_ASSERTION_NS}}}AttributeValue'
            ):
                if attr_value.text:
                    values.append(attr_value.text.strip())

            # Store by both Name and FriendlyName for flexible lookup
            if attr_name:
                attributes[attr_name] = values
            if attr_friendly and attr_friendly != attr_name:
                attributes[attr_friendly] = values

        return attributes

    def get_signature_info(self):
        """Extract signature information (for verification purposes)."""
        # Check Response-level signature
        response_sig = self.root.find(f'{{{XMLDSIG_NS}}}Signature')

        # Check Assertion-level signature
        assertion = self.get_assertion()
        assertion_sig = None
        if assertion is not None:
            assertion_sig = assertion.find(f'{{{XMLDSIG_NS}}}Signature')

        return {
            'response_signed': response_sig is not None,
            'assertion_signed': assertion_sig is not None,
        }


