import base64
import logging
from cryptography import x509
from cryptography.hazmat.primitives import hashes, serialization
from cryptography.hazmat.primitives.asymmetric import padding
from cryptography.exceptions import InvalidSignature

logger = logging.getLogger(__name__)


class SAMLSignatureVerifier:
    """Verifies SAML response signatures using IdP certificate."""

    def __init__(self, idp_cert_path=None, idp_cert_string=None):
        self.certificate = None
        self.public_key = None

        if idp_cert_path:
            self._load_cert_from_file(idp_cert_path)
        elif idp_cert_string:
            self._load_cert_from_string(idp_cert_string)

    def _load_cert_from_file(self, cert_path):
        """Load IdP certificate from file."""
        try:
            with open(cert_path, 'rb') as f:
                cert_data = f.read()
            self._load_cert(cert_data)
        except FileNotFoundError:
            logger.error(f"IdP certificate file not found: {cert_path}")
            raise
        except Exception as e:
            logger.error(f"Error loading IdP certificate: {e}")
            raise

    def _load_cert_from_string(self, cert_string):
        """Load IdP certificate from PEM string."""
        if isinstance(cert_string, str):
            # Ensure proper PEM formatting
            if '-----BEGIN CERTIFICATE-----' not in cert_string:
                cert_string = (
                    '-----BEGIN CERTIFICATE-----\n'
                    + cert_string +
                    '\n-----END CERTIFICATE-----'
                )
            cert_data = cert_string.encode('utf-8')
        else:
            cert_data = cert_string
        self._load_cert(cert_data)

    def _load_cert(self, cert_data):
        """Parse X.509 certificate."""
        try:
            self.certificate = x509.load_pem_x509_certificate(cert_data)
            self.public_key = self.certificate.public_key()
        except Exception:
            try:
                self.certificate = x509.load_der_x509_certificate(cert_data)
                self.public_key = self.certificate.public_key()
            except Exception as e:
                logger.error(f"Failed to parse certificate: {e}")
                raise

    def verify_response_signature(self, xml_string):
        """
        Basic signature presence check.
        For production, use a full XML signature verification library like signxml.
        """
        if self.public_key is None:
            logger.warning(
                "No IdP certificate loaded. Skipping signature verification."
            )
            return False

        # NOTE: Full XML Digital Signature verification requires canonicalization
        # and proper digest verification. For production use, integrate with
        # the 'signxml' library. This is a basic presence check.
        try:
            from signxml import XMLVerifier
            verifier = XMLVerifier()
            verified_data = verifier.verify(
                xml_string,
                x509_cert=self.certificate.public_bytes(
                    serialization.Encoding.PEM
                )
            )
            logger.info("SAML signature verified successfully.")
            return True
        except ImportError:
            logger.warning(
                "signxml library not installed. "
                "Install it for full signature verification: "
                "pip install signxml"
            )
            # Fall back to basic check
            return self._basic_signature_check(xml_string)
        except Exception as e:
            logger.error(f"Signature verification failed: {e}")
            return False

    def _basic_signature_check(self, xml_string):
        """Basic check that a signature element exists."""
        if isinstance(xml_string, bytes):
            xml_string = xml_string.decode('utf-8')
        has_signature = 'Signature' in xml_string and 'SignatureValue' in xml_string
        if has_signature:
            logger.warning(
                "Signature element found but not cryptographically verified. "
                "Install 'signxml' for proper verification."
            )
        return has_signature


