import base64
import zlib
import logging
from django.conf import settings
from .xml_validator import SAMLXMLValidator
from .signature_verifier import SAMLSignatureVerifier
from .exceptions import (
    SAMLError,
    SAMLValidationError,
    SAMLAttributeError,
)

logger = logging.getLogger(__name__)


class SAMLResponseProcessor:
    """Processes SAML POST responses."""

    def __init__(self):
        self.config = getattr(settings, 'SAML_SP_CONFIG', {})
        self.attribute_mapping = self.config.get('attribute_mapping', {})
        self.required_attributes = self.config.get('required_attributes', [])

    def process_response(self, saml_response_b64, relay_state=None):
        """
        Process a base64-encoded SAML Response from POST binding.

        Returns a dict with user information extracted from the assertion.
        """
        # Step 1: Decode the base64 SAML Response
        xml_string = self._decode_response(saml_response_b64)
        logger.debug("SAML Response decoded successfully.")

        # Step 2: Parse and validate XML structure
        validator = SAMLXMLValidator(xml_string)
        validator.validate_structure()
        logger.info("SAML XML structure validated successfully.")

        # Step 3: Verify signature (if IdP cert is configured)
        idp_cert = self.config.get('idp_cert')
        if idp_cert:
            verifier = SAMLSignatureVerifier(idp_cert_path=idp_cert)
            sig_valid = verifier.verify_response_signature(xml_string)
            if not sig_valid:
                logger.warning(
                    "SAML signature could not be verified."
                )
            else:
                logger.info("SAML signature verified.")

        # Step 4: Extract user information
        name_id_info = validator.get_name_id()
        attributes = validator.get_attributes()
        session_index = validator.get_session_index()
        issuer = validator.get_issuer()
        response_id = validator.get_response_id()
        assertion_id = validator.get_assertion_id()

        # Step 5: Map attributes to user fields
        mapped_attributes = self._map_attributes(attributes)

        # Step 6: Check required attributes
        self._check_required_attributes(mapped_attributes)

        result = {
            'name_id': name_id_info['value'],
            'name_id_format': name_id_info.get('format', ''),
            'session_index': session_index,
            'issuer': issuer,
            'response_id': response_id,
            'assertion_id': assertion_id,
            'attributes': mapped_attributes,
            'raw_attributes': attributes,
            'relay_state': relay_state,
        }

        logger.info(
            f"SAML Response processed successfully for NameID: "
            f"{name_id_info['value']}"
        )
        return result

    def _decode_response(self, saml_response_b64):
        """Decode base64-encoded SAML Response."""
        try:
            if isinstance(saml_response_b64, str):
                saml_response_b64 = saml_response_b64.encode('utf-8')

            xml_bytes = base64.b64decode(saml_response_b64)

            # Try to decode as UTF-8
            try:
                xml_string = xml_bytes.decode('utf-8')
            except UnicodeDecodeError:
                # Try deflate decompression (some IdPs compress)
                try:
                    xml_bytes = zlib.decompress(xml_bytes, -15)
                    xml_string = xml_bytes.decode('utf-8')
                except Exception:
                    xml_string = xml_bytes.decode('latin-1')

            return xml_string

        except Exception as e:
            raise SAMLValidationError(
                f"Failed to decode SAML Response: {str(e)}"
            )

    def _map_attributes(self, raw_attributes):
        """Map SAML attributes to Django user fields using configuration."""
        mapped = {}

        for saml_attr, django_field in self.attribute_mapping.items():
            if saml_attr in raw_attributes:
                values = raw_attributes[saml_attr]
                # Take the first value for single-valued fields
                mapped[django_field] = values[0] if len(values) == 1 else values

        return mapped

    def _check_required_attributes(self, mapped_attributes):
        """Verify all required attributes are present."""
        missing = []
        for attr in self.required_attributes:
            if attr not in mapped_attributes or not mapped_attributes[attr]:
                missing.append(attr)

        if missing:
            raise SAMLAttributeError(
                f"Required SAML attributes missing: {', '.join(missing)}"
            )


# saml_auth/auth_backend.py
import logging
from django.contrib.auth import get_user_model
from django.contrib.auth.backends import BaseBackend
from .models import SAMLUserProfile

logger = logging.getLogger(__name__)
User = get_user_model()


class SAMLAuthenticationBackend(BaseBackend):
    """Django authentication backend for SAML."""

    def authenticate(self, request, saml_data=None, **kwargs):
        """
        Authenticate a user based on SAML assertion data.

        Creates or updates the user and their SAML profile.
        """
        if saml_data is None:
            return None

        name_id = saml_data.get('name_id')
        if not name_id:
            logger.error("No NameID in SAML data.")
            return None

        attributes = saml_data.get('attributes', {})

        try:
            # Try to find existing user by SAML profile
            try:
                saml_profile = SAMLUserProfile.objects.get(name_id=name_id)
                user = saml_profile.user
                logger.info(
                    f"Found existing SAML user: {user.username} "
                    f"(NameID: {name_id})"
                )
            except SAMLUserProfile.DoesNotExist:
                # Create new user
                user = self._create_user(name_id, attributes)
                saml_profile = SAMLUserProfile.objects.create(
                    user=user,
                    name_id=name_id,
                )
                logger.info(
                    f"Created new SAML user: {user.username} "
                    f"(NameID: {name_id})"
                )

            # Update user attributes
            self._update_user(user, attributes)

            # Update SAML profile
            self._update_saml_profile(saml_profile, saml_data)

            return user

        except Exception as e:
            logger.error(
                f"Error authenticating SAML user (NameID: {name_id}): {e}"
            )
            return None

    def get_user(self, user_id):
        """Get user by ID."""
        try:
            return User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return None

    def _create_user(self, name_id, attributes):
        """Create a new Django user from SAML data."""
        email = attributes.get('email', '')
        first_name = attributes.get('first_name', '')
        last_name = attributes.get('last_name', '')

        # Use email as username if available, otherwise use name_id
        username = email if email else name_id

        # Ensure username uniqueness
        base_username = username
        counter = 1
        while User.objects.filter(username=username).exists():
            username = f"{base_username}_{counter}"
            counter += 1

        user = User.objects.create_user(
            username=username,
            email=email,
            first_name=first_name,
            last_name=last_name,
        )
        # SAML users shouldn't have a usable password
        user.set_unusable_password()
        user.save()

        return user

    def _update_user(self, user, attributes):
        """Update user fields from SAML attributes."""
        updated = False

        if 'email' in attributes and attributes['email']:
            if user.email != attributes['email']:
                user.email = attributes['email']
                updated = True

        if 'first_name' in attributes and attributes['first_name']:
            if user.first_name != attributes['first_name']:
                user.first_name = attributes['first_name']
                updated = True

        if 'last_name' in attributes and attributes['last_name']:
            if user.last_name != attributes['last_name']:
                user.last_name = attributes['last_name']
                updated = True

        if updated:
            user.save()
            logger.debug(f"Updated user attributes for {user.username}")

    def _update_saml_profile(self, profile, saml_data):
        """Update SAML profile with latest assertion data."""
        attributes = saml_data.get('attributes', {})
        profile.session_index = saml_data.get('session_index', '')
        profile.idp_entity_id = saml_data.get('issuer', '')
        profile.role = attributes.get('role', '')
        profile.department = attributes.get('department', '')
        profile.attributes_json = saml_data.get('raw_attributes', {})
        profile.save()


# saml_auth/views.py
import logging
import uuid
from datetime import datetime, timezone
from urllib.parse import urlencode

from django.conf import settings
from django.contrib import auth
from django.contrib.auth.decorators import login_required
from django.http import HttpResponse, HttpResponseBadRequest, JsonResponse
from django.shortcuts import redirect, render
from django.utils.decorators import method_decorator
from django.views import View
from django.views.decorators.csrf import csrf_exempt
from django.views.decorators.http import require_POST

from .exceptions import SAMLError, SAMLValidationError
from .models import SAMLResponseLog
from .saml_processor import SAMLResponseProcessor

logger = logging.getLogger(__name__)


def get_client_ip(request):
    """Get client IP address from request."""
    x_forwarded_for = request.META.get('HTTP_X_FORWARDED_FOR')
    if x_forwarded_for:
        return x_forwarded_for.split(',')[0].strip()
    return request.META.get('REMOTE_ADDR')


class SAMLLoginView(View):
    """Initiates SAML authentication by redirecting to IdP."""

    def get(self, request):
        config = getattr(settings, 'SAML_SP_CONFIG', {})
        idp_sso_url = config.get('idp_sso_url')

        if not idp_sso_url:
            return HttpResponseBadRequest("SAML IdP SSO URL not configured.")

        # Build SAML AuthnRequest
        authn_request_id = f"_{''.join(str(uuid.uuid4()).split('-'))}"
        issue_instant = datetime.now(timezone.utc).strftime(
            '%Y-%m-%dT%H:%M:%SZ'
        )
        entity_id = config.get('entity_id', '')
        acs_url = config.get('acs_url', '')

        authn_request = f"""<?xml version="1.0" encoding="UTF-8"?>
<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{authn_request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{idp_sso_url}"
    AssertionConsumerServiceURL="{acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{entity_id}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>"""

        import base64
        import zlib

        # Compress and encode for redirect binding
        compressed = zlib.compress(authn_request.encode('utf-8'))[2:-4]
        encoded = base64.b64encode(compressed).decode('utf-8')

        # Store the next URL in session
        next_url = request.GET.get('next', settings.LOGIN_REDIRECT_URL)
        request.session['saml_next_url'] = next_url
        request.session['saml_request_id'] = authn_request_id

        # Build redirect URL
        params = {
            'SAMLRequest': encoded,
        }
        relay_state = request.GET.get('RelayState', next_url)
        if relay_state:
            params['RelayState'] = relay_state

        redirect_url = f"{idp_sso_url}?{urlencode(params)}"
        return redirect(redirect_url)


@method_decorator(csrf_exempt, name='dispatch')
class SAMLACSView(View):
    """
    Assertion Consumer Service - handles SAML POST responses from IdP.
    """

    def post(self, request):
        """Handle SAML POST binding response."""
        saml_response_b64 = request.POST.get('SAMLResponse')
        relay_state = request.POST.get('RelayState')

        if not saml_response_b64:
            logger.error("No SAMLResponse in POST data.")
            return HttpResponseBadRequest("Missing SAMLResponse parameter.")

        ip_address = get_client_ip(request)
        user_agent = request.META.get('HTTP_USER_AGENT', '')

        try:
            # Process the SAML response
            processor = SAMLResponseProcessor()
            saml_data = processor.process_response(
                saml_response_b64, relay_state
            )

            # Log successful response
            SAMLResponseLog.objects.create(
                response_id=saml_data.get('response_id'),
                assertion_id=saml_data.get('assertion_id'),
                name_id=saml_data.get('name_id'),
                idp_entity_id=saml_data.get('issuer'),
                status='success',
                ip_address=ip_address,
                user_agent=user_agent,
            )

            # Authenticate user
            user = auth.authenticate(
                request,
                saml_data=saml_data,
            )

            if user is None:
                logger.error("SAML authentication returned no user.")
                return render(
                    request,
                    'saml_auth/error.html',
                    {
                        'error_title': 'Authentication Failed',
                        'error_message': (
                            'Unable to authenticate with the provided '
                            'SAML credentials. Please contact your '
                            'administrator.'
                        ),
                    },
                    status=403,
                )

            if not user.is_active:
                logger.warning(
                    f"SAML user {user.username} is inactive."
                )
                return render(
                    request,
                    'saml_auth/error.html',
                    {
                        'error_title': 'Account Disabled',
                        'error_message': (
                            'Your account has been disabled. '
                            'Please contact your administrator.'
                        ),
                    },
                    status=403,
                )

            # Log the user in and create session
            auth.login(request, user, backend='saml_auth.auth_backend.SAMLAuthenticationBackend')

            # Store SAML session data
            request.session['saml_session_index'] = saml_data.get(
                'session_index'
            )
            request.session['saml_name_id'] = saml_data.get('name_id')
            request.session['saml_issuer'] = saml_data.get('issuer')
            request.session['saml_authenticated'] = True

            logger.info(
                f"User {user.username} logged in via SAML "
                f"(NameID: {saml_data.get('name_id')})"
            )

            # Redirect to RelayState or default
            next_url = (
                relay_state
                or request.session.pop('saml_next_url', None)
                or settings.LOGIN_REDIRECT_URL
            )

            # Basic validation of redirect URL to prevent open redirect
            if not next_url.startswith('/'):
                from urllib.parse import urlparse
                parsed = urlparse(next_url)
                allowed_hosts = settings.ALLOWED_HOSTS
                if parsed.hostname and parsed.hostname not in allowed_hosts:
                    next_url = settings.LOGIN_REDIRECT_URL

            return redirect(next_url)

        except SAMLValidationError as e:
            logger.error(f"SAML validation error: {e}")
            SAMLResponseLog.objects.create(
                status='validation_error',
                error_message=str(e),
                ip_address=ip_address,
                user_agent=user_agent,
            )
            return render(
                request,
                'saml_auth/error.html',
                {
                    'error_title': 'SAML Validation Error',
                    'error_message': str(e),
                },
                status=400,
            )

        except SAMLError as e:
            logger.error(f"SAML error: {e}")
            SAMLResponseLog.objects.create(
                status='error',
                error_message=str(e),
                ip_address=ip_address,
                user_agent=user_agent,
            )
            return render(
                request,
                'saml_auth/error.html',
                {
                    'error_title': 'SAML Error',
                    'error_message': str(e),
                },
                status=400,
            )

        except Exception as e:
            logger.exception(f"Unexpected error processing SAML response: {e}")
            SAMLResponseLog.objects.create(
                status='error',
                error_message=f"Unexpected error: {str(e)}",
                ip_address=ip_address,
                user_agent=user_agent,
            )
            return render(
                request,
                'saml_auth/error.html',
                {
                    'error_title': 'Internal Error',
                    'error_message': (
                        'An unexpected error occurred during authentication. '
                        'Please try again or contact your administrator.'
                    ),
                },
                status=500,
            )


class SAMLLogoutView(View):
    """Handle SAML logout."""

    def get(self, request):
        """Log out the user and optionally redirect to IdP SLO."""
        # Clear SAML session data
        saml_keys = [
            'saml_session_index', 'saml_name_id',
            'saml_issuer', 'saml_authenticated',
            'saml_next_url', 'saml_request_id',
        ]
        for key in saml_keys:
            request.session.pop(key, None)

        # Django logout
        auth.logout(request)

        # Optionally redirect to IdP SLO
        config = getattr(settings, 'SAML_SP_CONFIG', {})
        idp_slo_url = config.get('idp_slo_url')

        if idp_slo_url:
            return redirect(idp_slo_url)

        return redirect(settings.LOGIN_URL)


class SAMLMetadataView(View):
    """Serve SP metadata XML."""

    def get(self, request):
        config = getattr(settings, 'SAML_SP_CONFIG', {})
        entity_id = config.get('entity_id', '')
        acs_url = config.get('acs_url', '')

        metadata = f"""<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{entity_id}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:NameIDFormat>
            urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress
        </md:NameIDFormat>
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{acs_url}"
            index="1"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>"""

        return HttpResponse(
            metadata.strip(),
            content_type='application/xml'
        )


@login_required
def saml_user_info(request):
    """API endpoint to get current SAML user information."""
    user = request.user
    data = {
        'username': user.username,
        'email': user.email,
        'first_name': user.first_name,
        'last_name': user.last_name,
        'is_saml_authenticated': request.session.get(
            'saml_authenticated', False
        ),
    }

    try:
        profile = user.saml_profile
        data.update({
            'name_id': profile.name_id,
            'idp_entity_id': profile.idp_entity_id,
            'role': profile.role,
            'department': profile.department,
            'saml_attributes': profile.attributes_json,
            'last_login_via_saml': profile.last_login_via_saml.isoformat(),
        })
    except Exception:
        pass

    return JsonResponse(data)


