logger = logging.getLogger(__name__)


class SAMLSessionMiddleware:
    """
    Middleware to enforce SAML session validity.
    Checks that the SAML session is still valid for protected views.
    """

    def __init__(self, get_response):
        self.get_response = get_response
        self.exempt_urls = [
            '/saml/login/',
            '/saml/acs/',
            '/saml/logout/',
            '/saml/metadata/',
        ]

    def __call__(self, request):
        # Skip for exempt URLs
        path = request.path
        if any(path.startswith(url) for url in self.exempt_urls):
            return self.get_response(request)

        # Skip for non-authenticated users (let normal auth handle it)
        if not request.user.is_authenticated:
            return self.get_response(request)

        # Check if user was SAML-authenticated
        if request.session.get('saml_authenticated'):
            # Optionally verify session is still valid
            # (e.g., check session timeout, etc.)
            pass

        response = self.get_response(request)
        return response


