from django import template

register = template.Library()


@register.simple_tag(takes_context=True)
def is_saml_user(context):
    """Check if the current user is authenticated via SAML."""
    request = context.get('request')
    if request and hasattr(request, 'session'):
        return request.session.get('saml_authenticated', False)
    return False


@register.simple_tag(takes_context=True)
def saml_attribute(context, attribute_name):
    """Get a SAML attribute for the current user."""
    request = context.get('request')
    if request and hasattr(request, 'user') and request.user.is_authenticated:
        try:
            profile = request.user.saml_profile
            return profile.attributes_json.get(attribute_name, '')
        except Exception:
            pass
    return ''


