    """Tests for SAML response processing."""

    def test_process_valid_response(self):
        xml = build_saml_response()
        b64 = base64.b64encode(xml.encode('utf-8')).decode('utf-8')

        processor = SAMLResponseProcessor()
        result = processor.process_response(b64)

        self.assertEqual(result['name_id'], 'testuser@example.com')
        self.assertEqual(result['attributes']['email'], 'testuser@example.com')
        self.assertEqual(result['attributes']['first_name'], 'Test')
        self.assertEqual(result['attributes']['last_name'], 'User')
        self.assertEqual(result['session_index'], '_session123')

